async function init(){ const rawData = await fetch('./data/bidking_items_seed_v1.json').then((r) => r.json()); app.data = { ...rawData, items: rawData.items.map(normalizeEconomyItem) }; app.state.warehouse = app.state.warehouse.map(hydrateStoredItem); saveState(); bindNav(); renderAll(); }
function loadState(){ try { const parsed = JSON.parse(localStorage.getItem(STORAGE_KEY) || 'null'); if(!parsed) return structuredClone(DEFAULT_STATE); return { ...structuredClone(DEFAULT_STATE), ...parsed, toolInventory: { ...structuredClone(DEFAULT_STATE).toolInventory, ...(parsed.toolInventory || {}) }, warehouse: parsed.warehouse || [], history: parsed.history || [] }; } catch { return structuredClone(DEFAULT_STATE); } }
function saveState(){ localStorage.setItem(STORAGE_KEY, JSON.stringify(app.state)); }
function bindNav(){ els.nav.addEventListener('click', (event) => { const btn = event.target.closest('[data-view]'); if(btn) setView(btn.dataset.view); }); }
function setView(view){ if((view === 'auction' || view === 'settlement') && !app.session) view = 'auction-setup'; app.view = view; document.querySelectorAll('.nav-btn').forEach((btn) => btn.classList.toggle('is-active', btn.dataset.view === view)); const views = { home: els.home, 'auction-setup': els.setup, auction: els.auction, settlement: els.settlement, shop: els.shop, warehouse: els.warehouseView, docs: els.docs }; Object.values(views).forEach((node) => node.classList.remove('is-active')); views[view].classList.add('is-active'); }
function renderAll(){ renderTopbar(); renderHome(); renderSetup(); renderShop(); renderWarehouse(); renderDocs(); if(app.session){ renderAuction(); if(app.view === 'settlement') renderSettlement(); } setView(app.view); }
function renderTopbar(){ els.money.textContent = formatMoney(app.state.money); els.warehouse.textContent = String(app.state.warehouse.length); els.tools.textContent = String(Object.values(app.state.toolInventory).reduce((sum, n) => sum + n, 0)); }
function renderHome(){ const history = app.state.history.slice(-5).reverse(); els.home.innerHTML = `<div class="home-grid"><div class="panel"><h2 class="section-title">原型状态</h2><p class="muted">这版已经切到游戏界面思路：主地图选择、开始行动后随机子场景、五回合竞拍、滚动盲盒区、结算入仓。</p><div class="badge-row"><span class="badge">10 x 30 盲盒区</span><span class="badge">主地图选择</span><span class="badge">随机子场景</span><span class="badge">五轮轨迹</span><span class="badge">本地存档</span></div><div class="surface-card proto-cta"><h3>快速开始</h3><p class="muted">先选主地图，再在配置页选择角色和道具，点击开始行动后系统会扣入场消耗并随机子场景。</p><div class="inline-actions"><button class="primary-btn" id="goAuctionBtn">进入竞拍</button><button class="secondary-btn" id="goShopBtn">去商店</button></div></div></div><div class="panel"><h2 class="section-title">最近结算</h2><div class="summary-list">${history.length ? history.map((item) => `<div class="log-item"><strong>${item.result}</strong><br><span class="muted">${item.mapName} / ${item.subsceneName} / 成交价 ${formatMoney(item.finalBid)} / 盈亏 ${formatSigned(item.profit)}</span></div>`).join('') : '<div class="log-item">还没有竞拍记录。</div>'}</div></div></div>`; document.getElementById('goAuctionBtn').onclick = () => setView('auction-setup'); document.getElementById('goShopBtn').onclick = () => setView('shop'); }
function renderSetup(){ const selectedMap = getMap(app.setup.mapId); const selectedRole = getRole(app.setup.roleId); const economyText = describeMapEconomy(selectedMap); els.setup.innerHTML = `<div class="panel stage-map-panel"><div class="auction-header"><div><p class="eyebrow">拍卖大厅</p><h2 class="section-title">选择主地图</h2></div><div class="hero-kpis"><div class="kpi">当前资金 <strong>${formatMoney(app.state.money)}</strong></div><div class="kpi">盈利曲线 <strong>按地图递增</strong></div></div></div><div class="map-node-grid">${MAPS.map((map) => `<article class="map-card map-node ${map.id === app.setup.mapId ? 'is-selected' : ''}"><h3>${map.name}</h3><p class="meta-line">资产要求：${map.entryFunds ? formatMoney(map.entryFunds) : '不限'}</p><p class="meta-line">行动消耗：${formatMoney(map.consumeFunds)}</p><p class="meta-line">底仓区间：${formatMoney(map.economy.floorMin)} - ${formatMoney(map.economy.floorMax)}</p><p class="meta-line">整盒价值：${formatMoney(map.valueBands[0].min)} - ${formatMoney(map.valueBands[map.valueBands.length - 1].max)}</p><p class="meta-line">预期盈利：${Math.round(map.economy.profitMin * 100)}% - ${Math.round(map.economy.profitMax * 100)}%</p><button class="secondary-btn" data-map-id="${map.id}" ${app.state.money < map.entryFunds ? 'disabled' : ''}>${app.state.money < map.entryFunds ? '资金不足' : '选择主地图'}</button></article>`).join('')}</div></div><div class="setup-hero-layout"><div class="panel role-stage-panel"><h2 class="section-title">选择角色</h2><div class="role-grid role-stage-grid">${ROLES.map((role) => `<article class="role-card ${role.id === app.setup.roleId ? 'is-selected' : ''}"><h3>${role.name}</h3><p class="meta-line">${role.summary}</p><button class="secondary-btn" data-role-id="${role.id}">配置角色</button></article>`).join('')}</div></div><div class="panel config-stage-panel"><h2 class="section-title">当前出发配置</h2><div class="summary-list"><div class="log-item">主地图：<strong>${selectedMap.name}</strong></div><div class="log-item">资产要求：<strong>${selectedMap.entryFunds ? formatMoney(selectedMap.entryFunds) : '不限'}</strong></div><div class="log-item">行动消耗：<strong>${formatMoney(selectedMap.consumeFunds)}</strong></div><div class="log-item">地图曲线：<strong>${economyText}</strong></div><div class="log-item">拍卖轮数：<strong>5</strong></div><div class="log-item">竞拍人数：<strong>4 人</strong></div><div class="log-item">角色：<strong>${selectedRole.name}</strong></div></div><div class="surface-card tool-select-surface"><h3>配置道具</h3><p class="muted">最多带 5 种不同道具。点击开始行动时只会从库存扣除你带入的这 5 种。</p><div class="tool-grid compact-tool-grid">${TOOLS.map((tool) => { const count = app.state.toolInventory[tool.id] || 0; const selected = app.setup.toolIds.includes(tool.id); return `<article class="tool-card ${selected ? 'is-selected' : ''}"><h3>${tool.name}</h3><p class="meta-line">${tool.description}</p><div class="badge-row"><span class="badge">库存 ${count}</span><span class="badge">${formatMoney(tool.price)}</span></div><button class="secondary-btn" data-tool-id="${tool.id}" ${count <= 0 && !selected ? 'disabled' : ''}>${selected ? '取消' : '带入'}</button></article>`; }).join('')}</div></div><div class="inline-actions setup-actions"><button class="primary-btn" id="startAuctionBtn" ${(app.state.money < selectedMap.entryFunds || app.state.money < selectedMap.consumeFunds) ? 'disabled' : ''}>开始行动</button></div></div></div>`; els.setup.querySelectorAll('[data-map-id]').forEach((btn) => { btn.onclick = () => { app.setup.mapId = btn.dataset.mapId; renderSetup(); }; }); els.setup.querySelectorAll('[data-role-id]').forEach((btn) => { btn.onclick = () => { app.setup.roleId = btn.dataset.roleId; renderSetup(); }; }); els.setup.querySelectorAll('[data-tool-id]').forEach((btn) => { btn.onclick = () => toggleTool(btn.dataset.toolId); }); document.getElementById('startAuctionBtn').onclick = startAuction; }
function toggleTool(toolId){ if(app.setup.toolIds.includes(toolId)) app.setup.toolIds = app.setup.toolIds.filter((id) => id !== toolId); else if(app.setup.toolIds.length < 5) app.setup.toolIds = [...app.setup.toolIds, toolId]; renderSetup(); }
function renderShop(){ els.shop.innerHTML = `<div class="panel"><h2 class="section-title">商店</h2><p class="muted">所有角色都能买和用。局外库存可叠加，但单局每种仍只能带 1 个。</p><div class="shop-grid">${TOOLS.map((tool) => `<article class="shop-card"><h3>${tool.name}</h3><p class="meta-line">${tool.description}</p><div class="badge-row"><span class="badge">价格 ${formatMoney(tool.price)}</span><span class="badge">库存 ${app.state.toolInventory[tool.id] || 0}</span></div><button class="primary-btn" data-buy-tool="${tool.id}" ${app.state.money < tool.price ? 'disabled' : ''}>购买</button></article>`).join('')}</div></div>`; els.shop.querySelectorAll('[data-buy-tool]').forEach((btn) => { btn.onclick = () => buyTool(btn.dataset.buyTool); }); }
function renderWarehouse(){ const qualityCount = countByQuality(app.state.warehouse); const totalValue = sumItemsValue(app.state.warehouse); els.warehouseView.innerHTML = `<div class="panel"><div class="auction-header compact-header"><div><h2 class="section-title">仓库</h2><p class="muted">未快速卖出的藏品会先入仓，后续可以逐件出手或一次性清仓。</p></div><div class="hero-kpis"><div class="kpi">库存数量 <strong>${app.state.warehouse.length}</strong></div><div class="kpi">库存估值 <strong>${formatMoney(totalValue)}</strong></div></div></div><div class="badge-row">${Object.keys(QUALITY_META).map((quality) => `<span class="quality-chip ${QUALITY_META[quality].cls}">${quality} ${qualityCount[quality] || 0}</span>`).join('')}</div><div class="inline-actions warehouse-actions">${app.state.warehouse.length ? `<button class="secondary-btn" id="sellAllWarehouseBtn">全部出售</button>` : ''}</div><div class="warehouse-grid" style="margin-top:18px;">${app.state.warehouse.length ? app.state.warehouse.map((item, index) => `<article class="warehouse-card"><h3>${item.name}</h3><p class="meta-line">${item.category} / ${item.quality} / ${item.width}x${item.height}</p><div class="badge-row"><span class="quality-chip ${QUALITY_META[item.quality].cls}">${item.quality}</span><span class="badge">回收价 ${formatMoney(item.recyclePrice)}</span></div><div class="warehouse-text-preview">${item.width}x${item.height} 轮廓 / ${item.cells} 格</div><button class="secondary-btn" data-sell-item="${index}">直接出售</button></article>`).join('') : '<div class="log-item">仓库还是空的。</div>'}</div></div>`; els.warehouseView.querySelectorAll('[data-sell-item]').forEach((btn) => { btn.onclick = () => sellWarehouseItem(Number(btn.dataset.sellItem)); }); const sellAllBtn = document.getElementById('sellAllWarehouseBtn'); if(sellAllBtn) sellAllBtn.onclick = sellAllWarehouse; }
function renderDocs(){ els.docs.innerHTML = `<div class="panel"><h2 class="section-title">资料与规范</h2><div class="docs-grid">${DOCS.map(([title, path]) => `<article class="doc-card"><h3>${title}</h3><a class="primary-btn" href="${path}" target="_blank" rel="noreferrer" style="display:inline-block;text-decoration:none;">打开</a></article>`).join('')}</div></div>`; }
function startAuction(){ const map = getMap(app.setup.mapId); if(app.state.money < map.entryFunds) return alert('资产要求未满足。'); if(app.state.money < map.consumeFunds) return alert('资金不足以支付入场消耗。'); const missingTool = app.setup.toolIds.find((toolId) => (app.state.toolInventory[toolId] || 0) <= 0); if(missingTool) return alert('有道具库存不足，无法开始。'); app.state.money -= map.consumeFunds; app.setup.toolIds.forEach((toolId) => { app.state.toolInventory[toolId] -= 1; }); const role = getRole(app.setup.roleId); const subscene = randomPick(map.subscenes); const box = buildBlindBox(map, subscene); app.session = { map, subscene, box, round: 1, winnerId: null, finalBid: 0, secondBid: 0, publicLogs: [], publicInfos: [], settlement: null, player: createParticipant('player', '你', role, app.setup.toolIds.map(getTool)), aiPlayers: [1,2,3].map((index) => createAiParticipant(index)) }; applyRoundStart(); saveState(); renderAll(); setView('auction'); }
function createParticipant(id,name,role,tools,profile = null){ return { id, name, role, tools: tools.map((tool) => ({ ...tool, used: false })), profile, bid: 0, privateLogs: [], knowledge: {}, bidTrack: Array(5).fill('-'), toolTrack: Array(5).fill('-'), submitted: false, usedToolThisRound: false, lastToolName: '', lastBidReason: '' }; }
function createAiParticipant(index){ const profile = AI_ARCHETYPES[(index - 1) % AI_ARCHETYPES.length]; return createParticipant(`ai_${index}`, `AI-${index}`, randomPick(ROLES), shuffle([...TOOLS]).slice(0, 4), profile); }
function buildBlindBox(map, subscene){ const candidates = app.data.items; const valueBand = pickValueBand(map); const targetValue = randomInt(valueBand.min, valueBand.max); const floorValue = randomInt(map.economy.floorMin, Math.min(map.economy.floorMax, targetValue - 1000)); const expectedProfitRate = randomFloat(map.economy.profitMin, map.economy.profitMax); const expectedBid = roundToHundred(targetValue * (1 - expectedProfitRate)); const seedItems = []; const used = new Set(); let totalValue = 0; let attempts = 0; while(attempts < 1200 && seedItems.length < 42){ attempts += 1; if(totalValue >= targetValue * 0.76) break; const quality = weightedPick(map.qualityWeights); const category = weightedPick(subscene.weights); const exact = candidates.filter((item) => item.quality === quality && item.category === category && !used.has(item.id)); const fallback = candidates.filter((item) => item.category === category && !used.has(item.id)); const pool = exact.length ? exact : fallback; const item = randomPick(pool); if(!item) continue; const nextValue = totalValue + item.recyclePrice; const tooExpensiveEarly = totalValue < targetValue * 0.6 && nextValue > targetValue * 0.92 && attempts < 1000; if(tooExpensiveEarly) continue; used.add(item.id); seedItems.push({ ...item, revealId: item.id }); totalValue = nextValue; } const items = tuneBoxEconomy(placeItemsInGrid(seedItems, candidates, map, subscene), targetValue, floorValue); return { items, totalValue: sumItemsValue(items), totalCells: BOX_WIDTH * BOX_HEIGHT, floorValue, valueBand, targetValue, expectedBid, expectedProfitRate }; }
function placeItemsInGrid(items, candidates, map, subscene){ const occupancy = Array.from({ length: BOX_HEIGHT }, () => Array(BOX_WIDTH).fill(false)); const placed = []; const sorted = [...items].sort((a, b) => b.cells - a.cells || b.recyclePrice - a.recyclePrice); sorted.forEach((item) => { const positioned = tryPlaceItem(occupancy, { ...item }); if(positioned) placed.push(positioned); }); for(let y = 0; y < BOX_HEIGHT; y += 1){ for(let x = 0; x < BOX_WIDTH; x += 1){ if(occupancy[y][x]) continue; const filler = createFittingFillerItem(candidates, occupancy, map, subscene, placed.length, x, y); occupy(occupancy, x, y, filler.width, filler.height); filler.x = x; filler.y = y; placed.push(filler); } } return placed.sort((a, b) => a.y - b.y || a.x - b.x); }
function canPlace(grid,startX,startY,width,height){ if(startX + width > BOX_WIDTH || startY + height > BOX_HEIGHT) return false; for(let y=startY;y<startY+height;y+=1){ for(let x=startX;x<startX+width;x+=1){ if(grid[y][x]) return false; } } return true; }
function occupy(grid,startX,startY,width,height){ for(let y=startY;y<startY+height;y+=1){ for(let x=startX;x<startX+width;x+=1){ grid[y][x] = true; } } }
function tryPlaceItem(grid, item){ for(let y = 0; y < BOX_HEIGHT; y += 1){ for(let x = 0; x < BOX_WIDTH; x += 1){ if(canPlace(grid, x, y, item.width, item.height)){ occupy(grid, x, y, item.width, item.height); item.x = x; item.y = y; return item; } } } return null; }
function createFittingFillerItem(candidates, occupancy, map, subscene, index, x, y){ const fitting = candidates.filter((item) => canPlace(occupancy, x, y, item.width, item.height)); const nonSingle = fitting.filter((item) => item.cells > 1); const pool = nonSingle.length ? nonSingle : fitting.filter((item) => item.width === 1 && item.height === 1); const preferredCategory = weightedPick(subscene.weights); const preferredQuality = weightedPick(map.qualityWeights); const exact = pool.filter((item) => item.category === preferredCategory && item.quality === preferredQuality); const categoryOnly = pool.filter((item) => item.category === preferredCategory); const ranked = (exact.length ? exact : categoryOnly.length ? categoryOnly : pool).sort((a, b) => b.cells - a.cells || b.recyclePrice - a.recyclePrice); const topSlice = ranked.slice(0, Math.min(8, ranked.length)); const base = randomPick(topSlice.length ? topSlice : ranked); return { ...base, revealId: `${base.id}__fill_${index}_${x}_${y}` }; }
function applyRoundStart(){ const session = app.session; if(session.round === 1){ session.publicLogs.push(`[\u573a\u666f] \u8fdb\u5165 ${session.map.name}\uff0c\u5df2\u968f\u673a\u5b50\u573a\u666f\u3010${session.subscene.name}\u3011\u3002`); } const publicInfo = generatePublicInfo(session); session.publicInfos.push(publicInfo.text); session.publicLogs.push(`[\u516c\u5171] \u7b2c ${session.round} \u56de\u5408\uff1a${publicInfo.text}`); if(publicInfo.reveal) applyReveal(app.session.player, publicInfo.reveal, '[\u516c\u5171]'); applyRoleReveal(app.session.player); app.session.aiPlayers.forEach((ai) => applyRoleReveal(ai)); }
function generatePublicInfo(session){ const items = session.box.items; const qualityCount = countByQuality(items); const round = session.round; if(round === 1) return { text: `\u672c\u76d2\u603b\u85cf\u54c1\u6570\u4e3a ${items.length} \u4ef6\u3002` }; if(round === 2){ const item = getLargestItem(items); return { text: `\u573a\u666f\u6b8b\u7559\u7ebf\u7d22\u63ed\u793a\u4e86\u4e00\u4ef6\u5927\u578b\u8f6e\u5ed3\u3002`, reveal: { itemId: item.revealId, width: item.width, height: item.height } }; } if(round === 3){ const item = randomPick(items); return { text: `\u573a\u666f\u788e\u7247\u989d\u5916\u63ed\u793a\u4e86\u4e00\u4ef6\u85cf\u54c1\u7684\u54c1\u8d28\u3002`, reveal: { itemId: item.revealId, quality: item.quality } }; } if(round === 4){ const item = getHighestValueItem(items); return { text: `\u573a\u666f\u6b8b\u7559\u8bb0\u53f7\u6307\u5411\u4e00\u4ef6\u9ad8\u4ef7\u503c\u85cf\u54c1\u7684\u54c1\u8d28\u3002`, reveal: { itemId: item.revealId, quality: item.quality } }; } const item = sampleItems(items, 1)[0] || getLargestItem(items); return { text: `\u672c\u76d2\u7d2b\u8272\u53ca\u4ee5\u4e0a\u85cf\u54c1\u5171\u6709 ${(qualityCount['\u7d2b\u8272'] || 0) + (qualityCount['\u91d1\u8272'] || 0) + (qualityCount['\u7ea2\u8272'] || 0)} \u4ef6\u3002`, reveal: { itemId: item.revealId, width: item.width, height: item.height } }; }
function applyRoleReveal(participant){ const session = app.session; const items = session.box.items; const round = session.round; if(participant.role.type === 'category'){ const matches = items.filter((item) => item.category === participant.role.category); if(round === 1) participant.privateLogs.push(`[\u89d2\u8272] ${participant.role.category} \u5171 ${matches.length} \u4ef6\u3002`); if(round === 2){ matches.forEach((item) => applyReveal(participant, { itemId: item.revealId, width: item.width, height: item.height })); participant.privateLogs.push(`[\u89d2\u8272] \u5df2\u63ed\u793a ${matches.length} \u4ef6 ${participant.role.category} \u7684\u8f6e\u5ed3\u3002`); } if(round === 3){ matches.forEach((item) => applyReveal(participant, { itemId: item.revealId, quality: item.quality })); participant.privateLogs.push(`[\u89d2\u8272] \u5df2\u63ed\u793a ${matches.length} \u4ef6 ${participant.role.category} \u7684\u54c1\u8d28\u3002`); } if(round === 4){ matches.forEach((item) => applyReveal(participant, { itemId: item.revealId, quality: item.quality, width: item.width, height: item.height })); participant.privateLogs.push(`[\u89d2\u8272] \u5df2\u5b8c\u5168\u63ed\u793a ${matches.length} \u4ef6 ${participant.role.category}\u3002`); } return; } if(participant.role.id === 'role_08' && round === 1){ const count = items.filter((item) => ['\u7d2b\u8272','\u91d1\u8272','\u7ea2\u8272'].includes(item.quality)).length; participant.privateLogs.push(`[\u89d2\u8272] \u7d2b\u91d1\u7ea2\u603b\u6570\u4e3a ${count}\u3002`); } if(participant.role.id === 'role_09' && round === 1){ const item = getHighestValueItem(items); applyReveal(participant, { itemId: item.revealId, quality: item.quality }); participant.privateLogs.push(`[\u89d2\u8272] \u6700\u9ad8\u4ef7\u85cf\u54c1\u54c1\u8d28\u4e3a ${item.quality}\u3002`); } if(participant.role.id === 'role_10'){ const sample = sampleUnknownQualityItems(participant, items, round === 1 ? 5 : 2); sample.forEach((item) => applyReveal(participant, { itemId: item.revealId, quality: item.quality })); participant.privateLogs.push(`[\u89d2\u8272] \u672c\u56de\u5408\u62bd\u6837\u63ed\u793a ${sample.length} \u4ef6\u54c1\u8d28\u3002`); } if(participant.role.id === 'role_12'){ const sample = sampleUnknownOutlineItems(participant, items, round === 1 ? 5 : 2); sample.forEach((item) => applyReveal(participant, { itemId: item.revealId, width: item.width, height: item.height })); participant.privateLogs.push(`[\u89d2\u8272] \u672c\u56de\u5408\u62bd\u6837\u63ed\u793a ${sample.length} \u4ef6\u8f6e\u5ed3\u3002`); } }
function applyReveal(participant, reveal, prefix = ''){ const current = participant.knowledge[reveal.itemId] || {}; participant.knowledge[reveal.itemId] = { ...current, ...reveal }; if(prefix){ const parts = []; if(reveal.quality) parts.push(`品质 ${reveal.quality}`); if(reveal.width && reveal.height) parts.push(`轮廓 ${reveal.width}x${reveal.height}`); participant.privateLogs.push(`${prefix} 已揭示 ${parts.join(' / ')}。`); } }
function renderAuction(){ const session = app.session; const threshold = getThreshold(session.round); const secondBid = getSecondBid(session); const leader = getLeader(session); const player = session.player; const estimate = secondBid > 0 ? formatMoney(Math.ceil(secondBid * threshold.multiplier)) : '\u672a\u5f62\u6210'; els.auction.innerHTML = `<div class=\"auction-screen\"><div class=\"auction-left-column\"><div class=\"panel player-track-panel\"><div class=\"auction-header compact-header\"><div><p class=\"eyebrow\">${session.map.name}</p><h2 class=\"section-title\">\u7b2c ${session.round} \u8f6e</h2><p class=\"muted\">\u5b50\u573a\u666f\uff1a${session.subscene.name}</p></div><div class=\"hero-kpis\"><div class=\"kpi\">\u9608\u503c <strong>${threshold.label}</strong></div></div></div><div class=\"track-list\">${[player, ...session.aiPlayers].map((participant) => renderParticipantTrack(participant, leader)).join('')}</div></div></div><div class=\"auction-center-column\"><div class=\"panel info-stage-panel\"><div class=\"auction-header compact-header\"><div><h3>\u4fe1\u606f\u533a</h3><p class=\"muted\">\u516c\u5171\u4fe1\u606f\u4f1a\u6301\u7eed\u4fdd\u7559\uff0c\u79c1\u6709\u60c5\u62a5\u6309\u6700\u65b0\u8bb0\u5f55\u5012\u5e8f\u663e\u793a\u3002</p></div><div class=\"hero-kpis\"><div class=\"kpi\">\u9886\u5148\u8005 <strong>${leader ? leader.name : '\u6682\u65e0'}</strong></div><div class=\"kpi\">\u62cd\u4e0b\u53c2\u8003 <strong>${estimate}</strong></div></div></div><div class=\"info-stage-columns\"><div class=\"info-subpanel\"><div class=\"mini-title\">\u516c\u5171\u60c5\u62a5</div><div class=\"info-stage-list\">${session.publicInfos.map((text, index) => `<div class=\"log-item\"><strong>\u7b2c ${index + 1} \u8f6e</strong><br>${text}</div>`).join('')}</div></div><div class=\"info-subpanel\"><div class=\"mini-title\">\u516c\u5f00\u884c\u4e3a</div><div class=\"info-stage-list\">${session.publicLogs.slice().reverse().map((log) => `<div class=\"log-item public-log\">${log}</div>`).join('')}</div></div><div class=\"info-subpanel\"><div class=\"mini-title\">\u4f60\u7684\u79c1\u6709\u60c5\u62a5</div><div class=\"info-stage-list\">${player.privateLogs.slice().reverse().map((log) => `<div class=\"log-item private-log\">${log}</div>`).join('')}</div></div></div></div><div class=\"panel bid-stage-panel\"><div class=\"auction-header compact-header\"><div><h3>\u51fa\u4ef7\u4e0e\u9053\u5177</h3><p class=\"muted\">\u4f60\u6bcf\u56de\u5408\u53ea\u80fd\u4f7f\u7528 1 \u4e2a\u9053\u5177\uff0c\u5e76\u63d0\u4ea4 1 \u6b21\u51fa\u4ef7\u3002\u63d0\u4ea4\u540e\u4e0d\u53ef\u4fee\u6539\u3002</p></div><div class=\"hero-kpis\"><div class=\"kpi\">\u7b2c\u4e8c\u540d <strong>${formatMoney(secondBid)}</strong></div><div class=\"kpi\">\u672c\u8f6e\u72b6\u6001 <strong>${player.submitted ? '\u5df2\u63d0\u4ea4' : '\u5f85\u64cd\u4f5c'}</strong></div></div></div><div class=\"bid-stage-grid\"><div class=\"bid-entry-card\"><p class=\"muted\">\u5f53\u524d\u62cd\u4e0b\u53c2\u8003\u4ef7\uff1a${estimate}</p><input id=\"bidInput\" type=\"number\" min=\"0\" step=\"100\" value=\"${player.bid || ''}\" ${player.submitted ? 'disabled' : ''} /><div class=\"inline-actions\"><button class=\"pill-btn\" data-fill=\"1.2\">\u00d71.2</button><button class=\"pill-btn\" data-fill=\"1.4\">\u00d71.4</button><button class=\"pill-btn\" data-fill=\"1.6\">\u00d71.6</button></div><div class=\"inline-actions\"><button class=\"primary-btn\" id=\"submitBidBtn\" ${player.submitted ? 'disabled' : ''}>\u51fa\u4ef7</button><button class=\"secondary-btn\" id=\"skipBidBtn\" ${player.submitted ? 'disabled' : ''}>\u5f03\u6743</button></div></div><div class=\"tool-side-list\">${player.tools.map((tool) => `<article class=\"tool-card ${tool.used ? 'used' : ''}\"><h3>${tool.name}</h3><p class=\"meta-line\">${tool.description}</p><button class=\"tool-use-btn\" data-tool-use=\"${tool.id}\" ${tool.used || player.usedToolThisRound || player.submitted ? 'disabled' : ''}>${tool.used ? '\u5df2\u6d88\u8017' : '\u672c\u56de\u5408\u4f7f\u7528'}</button></article>`).join('')}</div></div></div></div><div class=\"auction-right-column\"><div class=\"panel blind-box-panel\"><div class=\"auction-header compact-header\"><div><h3>\u7ade\u54c1\u76f2\u76d2</h3><p class=\"muted\">\u533a\u57df\u56fa\u5b9a\u4e3a 10 x 30\u3002\u53ea\u5728\u83b7\u5f97\u5750\u6807\u7ea7\u60c5\u62a5\u540e\uff0c\u624d\u4f1a\u5728\u683c\u5b50\u4e2d\u663e\u73b0\u3002</p></div><div class=\"hero-kpis\"><div class=\"kpi\">\u603b\u683c\u6570 <strong>${BOX_WIDTH * BOX_HEIGHT}</strong></div><div class=\"kpi\">\u5df2\u63ed\u793a <strong>${Object.keys(session.player.knowledge).length}</strong></div></div></div><div class=\"blind-box-scroll\"><div class=\"blind-box-grid\">${renderBlindBox(session.player.knowledge, session.box.items)}</div></div></div></div></div>`; els.auction.querySelectorAll('[data-fill]').forEach((btn) => { btn.onclick = () => { const base = getSecondBid(session) || 50000; document.getElementById('bidInput').value = Math.ceil(base * Number(btn.dataset.fill)); }; }); els.auction.querySelectorAll('[data-tool-use]').forEach((btn) => { btn.onclick = () => useTool(btn.dataset.toolUse); }); document.getElementById('submitBidBtn').onclick = submitBid; document.getElementById('skipBidBtn').onclick = () => { document.getElementById('bidInput').value = 0; submitBid(); }; }
function renderParticipantTrack(participant, leader){ return `<article class="bidder-card track-card ${leader && leader.id === participant.id ? 'leading' : ''}"><h3>${participant.name}</h3><p class="meta-line">${participant.role.name}</p><div class="track-row"><span class="track-label">出价</span>${participant.bidTrack.map((bid) => `<span class="track-value">${bid}</span>`).join('')}</div><div class="track-row"><span class="track-label">道具</span>${participant.toolTrack.map((tool) => `<span class="track-value track-tool">${tool}</span>`).join('')}</div></article>`; }
function renderBlindBox(knowledge, items){ const entries = items.filter((item) => knowledge[item.revealId]).map((item) => ({ item, info: knowledge[item.revealId] })); if(!entries.length) return `<div class="empty-box-tip">\u60c5\u62a5\u5c1a\u672a\u63ed\u793a</div>`; return entries.map(({ item, info }) => { if(info.width && info.height){ const revealClass = info.quality ? '' : 'outline-only'; const blockStyle = `grid-column:${item.x + 1} / span ${info.width}; grid-row:${item.y + 1} / span ${info.height};`; return `<div class="blind-box-item ${revealClass} ${info.quality ? QUALITY_META[info.quality].cls : ''}" style="${blockStyle}"></div>`; } if(info.quality){ return `<div class="blind-box-token ${QUALITY_META[info.quality].cls}" style="grid-column:${item.x + 1}; grid-row:${item.y + 1};"></div>`; } return ''; }).join(''); }
function renderSettlementBox(items, revealed){ return items.map((item) => { const shown = revealed.has(item.revealId); const blockStyle = `grid-column:${item.x + 1} / span ${item.width}; grid-row:${item.y + 1} / span ${item.height};`; return `<div class="settlement-box-item ${shown ? QUALITY_META[item.quality].cls : 'outline-only'}" style="${blockStyle}">${shown ? `<div class=\"settlement-box-content\"><div class=\"settlement-box-name\">${item.name}</div><div class=\"settlement-box-price\">${formatMoney(item.recyclePrice)}</div></div>` : `<div class=\"settlement-box-loading\"><span class=\"loading-spinner\"></span></div>`}</div>`; }).join(''); }
function useTool(toolId){ const session = app.session; const player = session.player; const tool = player.tools.find((entry) => entry.id === toolId); if(!tool || tool.used || player.usedToolThisRound) return; applyToolEffect(player, tool); tool.used = true; player.usedToolThisRound = true; player.lastToolName = tool.name; player.toolTrack[session.round - 1] = tool.name; session.publicLogs.push(`[公开行为] 你 使用了【${tool.name}】`); renderAuction(); }
function applyToolEffect(participant, tool){ const items = app.session.box.items; if(tool.effect === 'highest_quality'){ const item = getHighestValueItem(items); applyReveal(participant, { itemId: item.revealId, quality: item.quality }); participant.privateLogs.push(`[道具] ${tool.name}：最高价藏品品质为 ${item.quality}。`); } if(tool.effect === 'rare_count'){ const count = items.filter((item) => ['紫色','金色','红色'].includes(item.quality)).length; participant.privateLogs.push(`[道具] ${tool.name}：紫金红总数为 ${count}。`); } if(tool.effect === 'has_red'){ participant.privateLogs.push(`[道具] ${tool.name}：${items.some((item) => item.quality === '红色') ? '检测到红色藏品。' : '未检测到红色藏品。'}`); } if(tool.effect === 'largest_outline'){ const item = getLargestItem(items); applyReveal(participant, { itemId: item.revealId, width: item.width, height: item.height }); participant.privateLogs.push(`[道具] ${tool.name}：最大轮廓为 ${item.width}x${item.height}。`); } if(tool.effect === 'highest_full'){ const item = getHighestValueItem(items); applyReveal(participant, { itemId: item.revealId, quality: item.quality, width: item.width, height: item.height }); participant.privateLogs.push(`[道具] ${tool.name}：已完全揭示最高价藏品。`); } if(tool.effect === 'quality_sample'){ const sample = sampleItems(items, 2); sample.forEach((item) => applyReveal(participant, { itemId: item.revealId, quality: item.quality })); participant.privateLogs.push(`[道具] ${tool.name}：随机揭示 ${sample.length} 件品质。`); } }
function submitBid(){ const player = app.session.player; player.bid = Math.max(0, Number(document.getElementById('bidInput').value || 0)); player.submitted = true; player.bidTrack[app.session.round - 1] = player.bid > 0 ? formatShortMoney(player.bid) : '-'; if(player.toolTrack[app.session.round - 1] === '-') player.toolTrack[app.session.round - 1] = player.lastToolName || '-'; runAiTurn(); resolveRound(); }
function runAiTurn(){ const currentTop = Math.max(...[app.session.player, ...app.session.aiPlayers].map((p) => p.bid), 0); app.session.aiPlayers.forEach((ai) => { ai.submitted = false; ai.usedToolThisRound = false; ai.lastToolName = ''; maybeUseAiTool(ai); ai.bid = decideAiBid(ai, currentTop); ai.submitted = true; ai.bidTrack[app.session.round - 1] = ai.bid > 0 ? formatShortMoney(ai.bid) : '-'; ai.toolTrack[app.session.round - 1] = ai.lastToolName || '-'; }); }
function maybeUseAiTool(ai){ const preferred = ai.tools.find((tool) => !tool.used && ['highest_full','highest_quality','largest_outline','rare_count'].includes(tool.effect)); if(!preferred || app.session.round > 3 || Math.random() > 0.72) return; applyToolEffect(ai, preferred); preferred.used = true; ai.usedToolThisRound = true; ai.lastToolName = preferred.name; app.session.publicLogs.push(`[公开行为] ${ai.name} 使用了【${preferred.name}】`); }
function decideAiBid(ai, currentTop){ const appetite = estimateAiAppetite(ai); const openingBid = roundToHundred(app.session.box.floorValue * randomFloat(0.58, 0.72) * ai.profile.opener); const minRaise = Math.max(1000, roundToHundred(Math.max(app.session.box.floorValue * 0.04, currentTop * randomFloat(0.05, 0.12)))); if(currentTop <= 0){ const candidate = Math.min(appetite, openingBid); ai.lastBidReason = candidate > 0 ? '主动开价' : '观望'; return candidate > 0 ? candidate : 0; } if(currentTop >= appetite * ai.profile.patience){ ai.lastBidReason = '超过接受价'; return 0; } const targetBid = Math.min(appetite, roundToHundred(currentTop + minRaise)); const bluffBid = roundToHundred(targetBid * (1 + ai.profile.bluff * Math.random())); const candidate = Math.min(appetite, Math.max(targetBid, bluffBid)); ai.lastBidReason = candidate > currentTop ? '跟进压价' : '谨慎收手'; return candidate > currentTop ? candidate : 0; }
function resolveRound(){ const ranking = [app.session.player, ...app.session.aiPlayers].map((participant) => ({ id: participant.id, name: participant.name, bid: participant.bid })).sort((a, b) => b.bid - a.bid); const first = ranking[0]; const second = ranking[1] || { bid: 0 }; const threshold = getThreshold(app.session.round); const success = app.session.round === 5 ? first.bid > 0 : first.bid >= Math.ceil(second.bid * threshold.multiplier); app.session.finalBid = first.bid; app.session.secondBid = second.bid; if(success){ finishAuction(first.id, first.bid); return; } app.session.publicLogs.push(`[回合结论] 第 ${app.session.round} 回合未拍下，领先价 ${formatMoney(first.bid)}，第二名 ${formatMoney(second.bid)}。`); advanceRound(); }
function advanceRound(){ app.session.round += 1; [app.session.player, ...app.session.aiPlayers].forEach((participant) => { participant.submitted = false; participant.usedToolThisRound = false; participant.lastToolName = ''; }); applyRoundStart(); renderAuction(); }
function finishAuction(winnerId, bid){ app.session.winnerId = winnerId; app.session.finalBid = bid; const winnerName = [app.session.player, ...app.session.aiPlayers].find((participant) => participant.id === winnerId)?.name || '未知'; app.session.publicLogs.push(`[拍下] ${winnerName} 以 ${formatMoney(bid)} 拍下盲盒。`); beginSettlement(); }
function beginSettlement(){ clearTimers(); app.session.settlement = { revealedIds: [], revealedValue: 0, selectedColors: Object.keys(QUALITY_META), skipped: false }; const revealOrder = [...app.session.box.items].sort((a, b) => a.y - b.y || a.x - b.x); for(let index = 0; index < revealOrder.length; index += SETTLEMENT_REVEAL_BATCH){ const batch = revealOrder.slice(index, index + SETTLEMENT_REVEAL_BATCH); const handle = window.setTimeout(() => { if(!app.session || app.session.settlement.skipped) return; batch.forEach((item) => revealSettlementItem(item)); renderSettlement(); }, (index / SETTLEMENT_REVEAL_BATCH) * SETTLEMENT_REVEAL_INTERVAL); app.timers.push(handle); } renderSettlement(); setView('settlement'); }
function renderSettlement(){ const settlement = app.session.settlement; const revealed = new Set(settlement.revealedIds); const playerWon = app.session.winnerId === 'player'; const currentProfit = settlement.revealedValue - app.session.finalBid; const selectionSummary = summarizeSettlementSelection(settlement.selectedColors); const allShown = settlement.revealedIds.length === app.session.box.items.length; els.settlement.innerHTML = `<div class="settlement-grid settlement-photo-layout"><div class="panel settlement-summary-panel"><p class="eyebrow">${app.session.subscene.name}</p><h2 class="section-title">对局结算</h2><div class="summary-list settlement-number-list"><div class="log-item">拍得者：<strong>${playerWon ? '你' : 'AI 对手'}</strong></div><div class="log-item">成交价：<strong>${formatMoney(app.session.finalBid)}</strong></div><div class="log-item">已揭示价值：<strong>${formatMoney(settlement.revealedValue)}</strong></div><div class="log-item">当前利润：<strong class="${currentProfit >= 0 ? 'money-positive' : 'money-negative'}">${formatSigned(currentProfit)}</strong></div></div>${playerWon ? `<div class="surface-card settlement-sell-surface"><h3>快速回收</h3><div class="checkbox-row quality-checkboxes">${Object.keys(QUALITY_META).map((quality) => `<label><input type="checkbox" data-sell-color="${quality}" ${settlement.selectedColors.includes(quality) ? 'checked' : ''}/> ${quality}</label>`).join('')}</div><p class="footer-note">默认全选，代表这批颜色会直接卖出。取消勾选的颜色会进入仓库。当前策略：${selectionSummary}</p></div>` : '<div class="surface-card settlement-sell-surface"><h3>你未拍下本盒</h3><p class="muted">本次仅观看揭示，不获得战利品。</p></div>'}<div class="inline-actions"><button class="primary-btn" id="finishSettlementBtn">完成结算</button>${!allShown ? '<button class="secondary-btn" id="skipSettlementBtn">跳过鉴定</button>' : ''}<button class="secondary-btn" id="returnHomeBtn">返回大厅</button></div></div><div class="panel settlement-items-panel"><div class="auction-header compact-header"><div><h3>战利品仓位</h3><p class="muted">已缩短鉴定节奏，你也可以直接跳过动画显示全部藏品与价值。</p></div><div class="hero-kpis"><div class="kpi">已鉴定 <strong>${settlement.revealedIds.length}/${app.session.box.items.length}</strong></div><div class="kpi">底仓参考 <strong>${formatMoney(app.session.box.floorValue)}</strong></div></div></div><div class="settlement-box-scroll"><div class="blind-box-grid settlement-box-grid">${renderSettlementBox(app.session.box.items, revealed)}</div></div></div></div>`; els.settlement.querySelectorAll('[data-sell-color]').forEach((input) => { input.onchange = () => { const color = input.dataset.sellColor; settlement.selectedColors = input.checked ? [...settlement.selectedColors, color] : settlement.selectedColors.filter((entry) => entry !== color); renderSettlement(); }; }); document.getElementById('finishSettlementBtn').onclick = finalizeSettlement; const skipBtn = document.getElementById('skipSettlementBtn'); if(skipBtn) skipBtn.onclick = skipSettlementReveal; document.getElementById('returnHomeBtn').onclick = () => { app.session = null; clearTimers(); renderAll(); setView('home'); }; }
function finalizeSettlement(){ clearTimers(); const playerWon = app.session.winnerId === 'player'; let profit = 0; if(playerWon){ const soldColors = new Set(app.session.settlement.selectedColors); let soldValue = 0; const kept = []; app.session.box.items.forEach((item) => { if(soldColors.has(item.quality)) soldValue += item.recyclePrice; else kept.push(item); }); app.state.money = app.state.money - app.session.finalBid + soldValue; app.state.warehouse = [...app.state.warehouse, ...kept]; profit = soldValue + sumItemsValue(kept) - app.session.finalBid; } app.state.history.push({ mapName: app.session.map.name, subsceneName: app.session.subscene.name, finalBid: app.session.finalBid, profit, result: playerWon ? '你拍下了盲盒' : 'AI 拍下了盲盒' }); saveState(); app.session = null; renderAll(); setView(playerWon ? 'warehouse' : 'home'); }
function buyTool(toolId){ const tool = getTool(toolId); if(app.state.money < tool.price) return; app.state.money -= tool.price; app.state.toolInventory[toolId] = (app.state.toolInventory[toolId] || 0) + 1; saveState(); renderAll(); }
function sellWarehouseItem(index){ const item = app.state.warehouse[index]; if(!item) return; app.state.money += item.recyclePrice; app.state.warehouse.splice(index, 1); saveState(); renderAll(); }
function sellAllWarehouse(){ if(!app.state.warehouse.length) return; app.state.money += sumItemsValue(app.state.warehouse); app.state.warehouse = []; saveState(); renderAll(); }
function getMap(id){ return MAPS.find((map) => map.id === id) || MAPS[0]; }
function getRole(id){ return ROLES.find((role) => role.id === id) || ROLES[0]; }
function getTool(id){ return TOOLS.find((tool) => tool.id === id); }
function randomPick(array){ return array[Math.floor(Math.random() * array.length)]; }
function randomInt(min,max){ return Math.floor(Math.random() * (max - min + 1)) + min; }
function shuffle(array){ return [...array].sort(() => Math.random() - 0.5); }
function sampleItems(items,count){ return shuffle(items).slice(0, count); }
function sampleUnknownQualityItems(participant, items, count){ const unknown = items.filter((item) => !participant.knowledge[item.revealId]?.quality); return shuffle(unknown.length ? unknown : items).slice(0, count); }
function sampleUnknownOutlineItems(participant, items, count){ const unknown = items.filter((item) => !participant.knowledge[item.revealId]?.width || !participant.knowledge[item.revealId]?.height); return shuffle(unknown.length ? unknown : items).slice(0, count); }
function countByQuality(items){ return items.reduce((acc, item) => ((acc[item.quality] = (acc[item.quality] || 0) + 1), acc), {}); }
function countByCategory(items){ return items.reduce((acc, item) => ((acc[item.category] = (acc[item.category] || 0) + 1), acc), {}); }
function getHighestValueItem(items){ return [...items].sort((a, b) => b.recyclePrice - a.recyclePrice)[0]; }
function getLargestItem(items){ return [...items].sort((a, b) => b.cells - a.cells || b.recyclePrice - a.recyclePrice)[0]; }
function weightedPick(weights){ const entries = Object.entries(weights); const total = entries.reduce((sum, [, weight]) => sum + weight, 0); let cursor = Math.random() * total; for(const [value, weight] of entries){ cursor -= weight; if(cursor <= 0) return value; } return entries[entries.length - 1][0]; }
function normalizeEconomyItem(item){ const perCell = QUALITY_PRICE_PER_CELL[item.quality] || 120; const categoryFactor = CATEGORY_PRICE_FACTOR[item.category] || 1; const sizeFactor = 1 + Math.max(0, item.cells - 1) * 0.24; const shapeFactor = item.width > 1 && item.height > 1 ? 1.05 : 1; const rarityFactor = item.cells >= 6 ? 1.08 : 1; const rawPrice = perCell * sizeFactor * categoryFactor * shapeFactor * rarityFactor; const normalizedPrice = Math.max(perCell, roundToHundred(rawPrice)); return { ...item, recyclePrice: normalizedPrice }; }
function pickValueBand(map){ const bands = map.valueBands; const total = bands.reduce((sum, band) => sum + band.weight, 0); let cursor = Math.random() * total; for(const band of bands){ cursor -= band.weight; if(cursor <= 0) return band; } return bands[bands.length - 1]; }
function tuneBoxEconomy(items, targetValue, floorValue){ const rawTotal = Math.max(1, sumItemsValue(items)); const scaledItems = items.map((item) => ({ ...item, recyclePrice: Math.max(100, roundToHundred(item.recyclePrice * (targetValue / rawTotal))) })); const scaledTotal = sumItemsValue(scaledItems); const delta = roundToHundred(targetValue - scaledTotal); if(delta !== 0){ const targetItem = [...scaledItems].sort((a, b) => b.recyclePrice - a.recyclePrice)[0]; targetItem.recyclePrice = Math.max(100, targetItem.recyclePrice + delta); } const finalItems = scaledItems.sort((a, b) => a.y - b.y || a.x - b.x); const finalTotal = sumItemsValue(finalItems); if(finalTotal < floorValue){ const premium = roundToHundred(floorValue - finalTotal); const targetItem = [...finalItems].sort((a, b) => b.recyclePrice - a.recyclePrice)[0]; targetItem.recyclePrice += premium; } return finalItems; }
function describeMapEconomy(map){ return `底仓 ${formatShortMoney(map.economy.floorMin)}-${formatShortMoney(map.economy.floorMax)} / 利润 ${Math.round(map.economy.profitMin * 100)}%-${Math.round(map.economy.profitMax * 100)}%`; }
function hydrateStoredItem(item){ return Number.isFinite(item?.recyclePrice) && item.recyclePrice > 0 ? item : normalizeEconomyItem(item); }
function estimateAiAppetite(ai){ const session = app.session; const revealedValue = getKnownValue(ai); const knownRatio = getKnowledgeCoverage(ai); const infoEdge = ai.lastToolName ? 0.05 : 0; const roleEdge = ai.role.type === 'category' ? 0.06 : 0.03; const curveWeight = Math.min(0.94, 0.28 + session.round * 0.14 + knownRatio * 0.22 + infoEdge + roleEdge); const estimate = session.box.floorValue + (session.box.totalValue - session.box.floorValue) * curveWeight * ai.profile.infoBias; const pressureCap = session.box.expectedBid * session.map.economy.aiPressure; return roundToHundred(Math.min(estimate * ai.profile.risk + revealedValue * 0.18, pressureCap * (0.96 + Math.random() * 0.08))); }
function getKnownValue(participant){ return app.session.box.items.reduce((sum, item) => { const info = participant.knowledge[item.revealId]; if(!info) return sum; const detail = Number(Boolean(info.quality)) + Number(Boolean(info.width && info.height)); const weight = detail === 2 ? 0.9 : detail === 1 ? 0.45 : 0; return sum + item.recyclePrice * weight; }, 0); }
function getKnowledgeCoverage(participant){ return app.session.box.items.reduce((sum, item) => { const info = participant.knowledge[item.revealId]; if(!info) return sum; return sum + (Number(Boolean(info.quality)) + Number(Boolean(info.width && info.height))) / 2; }, 0) / app.session.box.items.length; }
function revealSettlementItem(item){ if(app.session && !app.session.settlement.revealedIds.includes(item.revealId)){ app.session.settlement.revealedIds.push(item.revealId); app.session.settlement.revealedValue += item.recyclePrice; } }
function skipSettlementReveal(){ if(!app.session) return; clearTimers(); app.session.settlement.skipped = true; app.session.box.items.forEach((item) => revealSettlementItem(item)); renderSettlement(); }
function summarizeSettlementSelection(selectedColors){ if(selectedColors.length === Object.keys(QUALITY_META).length) return '全部快速卖出'; if(!selectedColors.length) return '全部进入仓库'; return `卖出 ${selectedColors.join(' / ')}`; }
function getLeader(session = app.session){ return [session.player, ...session.aiPlayers].sort((a, b) => b.bid - a.bid)[0] || null; }
function getSecondBid(session = app.session){ const bids = [session.player, ...session.aiPlayers].map((p) => p.bid).sort((a, b) => b - a); return bids[1] || 0; }
function getThreshold(round){ return { 1: { multiplier: 2.0, label: '>= 第二名 × 2.0' }, 2: { multiplier: 1.6, label: '>= 第二名 × 1.6' }, 3: { multiplier: 1.4, label: '>= 第二名 × 1.4' }, 4: { multiplier: 1.2, label: '>= 第二名 × 1.2' }, 5: { multiplier: 1.0, label: '价高者直接拍下' } }[round]; }
function formatMoney(value){ return `${Math.round(value).toLocaleString('zh-CN')} 元`; }
function formatShortMoney(value){ return value >= 10000 ? `${(value / 10000).toFixed(1)}w` : `${Math.round(value)}`; }
function formatSigned(value){ return `${value >= 0 ? '+' : '-'}${Math.abs(Math.round(value)).toLocaleString('zh-CN')} 元`; }
function sumItemsValue(items){ return items.reduce((sum, item) => sum + item.recyclePrice, 0); }
function randomFloat(min,max){ return Math.random() * (max - min) + min; }
function roundToHundred(value){ return Math.round(value / 100) * 100; }
function clearTimers(){ app.timers.forEach((handle) => clearTimeout(handle)); app.timers = []; }
